// 📄 PAGE: Admin Manage Companies
// 🌐 URL: /admin/companies
// 👤 WHO: Admin only

import connectDB from '@/lib/db'
import Company from '@/models/Company'
import AdminCompanyActions from '@/components/dashboard/AdminCompanyActions'

export default async function AdminCompaniesPage() {
  await connectDB()

  const companies = await Company.find({ isEmailVerified: true })
    .sort({ createdAt: -1 })
    .lean()

  const planColors: Record<string, string> = {
    free:       'bg-slate-100 text-slate-700 border-slate-200/50',
    pro:        'bg-amber-500/10 text-amber-600 border-amber-500/20',
    enterprise: 'bg-emerald-500/10 text-emerald-600 border-emerald-500/20',
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <div>
        <h1 className="text-xl font-bold text-foreground">Manage Companies</h1>
        <p className="text-xs text-muted">{companies.length} registered companies awaiting verification or management</p>
      </div>

      <div className="space-y-4">
        {(companies as any[]).map(company => (
          <div 
            key={company._id.toString()} 
            className="premium-card p-5 rounded-2xl group hover:shadow-[0_4px_25px_rgba(0,0,0,0.015)] relative overflow-hidden"
          >
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">

              <div className="flex items-start gap-4">
                {/* Initial logo avatar */}
                <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-indigo-50 to-primary/5 border border-primary/10 flex items-center justify-center text-primary font-bold text-lg shrink-0 group-hover:scale-102 transition-transform">
                  {company.name?.charAt(0).toUpperCase() || '?'}
                </div>

                <div className="space-y-1">
                  <h3 className="text-sm font-bold text-foreground group-hover:text-primary transition-colors">{company.name}</h3>
                  <p className="text-[11px] text-muted">{company.email}</p>

                  <div className="flex gap-2 pt-1">
                    <span className="text-[9px] font-extrabold px-2 py-0.5 rounded-full bg-slate-50 border border-slate-100 text-muted uppercase tracking-wider">
                      {company.industry || 'Unknown Industry'}
                    </span>
                    <span className={`text-[9px] font-extrabold px-2 py-0.5 rounded-full border uppercase tracking-wider ${planColors[company.subscription?.plan] || planColors.free}`}>
                      {company.subscription?.plan || 'free'} plan
                    </span>
                  </div>
                </div>
              </div>

              {/* Admin Actions */}
              <AdminCompanyActions
                companyId={company._id.toString()}
                isApproved={company.isAdminApproved}
                companyName={company.name}
                companyEmail={company.email}
              />

            </div>
          </div>
        ))}
      </div>
    </div>
  )
}

// 📄 PAGE: Admin Manage Users
// 🌐 URL: /admin/users
// 👤 WHO: Admin only

import { getServerSession } from 'next-auth'
import { authOptions } from '@/utils/auth'
import { redirect } from 'next/navigation'
import connectDB from '@/lib/db'
import User from '@/models/User'
import AdminUsersList from '@/components/dashboard/AdminUsersList'

export default async function AdminUsersPage() {
  const session = await getServerSession(authOptions)
  if (!session || session.user.role !== 'admin') {
    redirect('/login')
  }

  await connectDB()

  // Fetch all users sorted by registration date
  const rawUsers = await User.find()
    .sort({ createdAt: -1 })
    .lean()

  // Serialize Mongoose models for Next.js Client Component compatibility
  const users = rawUsers.map((user: any) => ({
    _id: user._id.toString(),
    name: user.name || 'Unknown',
    email: user.email,
    role: user.role || 'jobseeker',
    isEmailVerified: !!user.isEmailVerified,
    createdAt: user.createdAt ? user.createdAt.toISOString() : new Date().toISOString(),
  }))

  return (
    <div className="space-y-6 animate-fade-in">
      <div>
        <h1 className="text-xl font-bold text-foreground">Manage Platform Users</h1>
        <p className="text-xs text-muted">
          {users.length} registered accounts across seekers, recruiters, and administrators
        </p>
      </div>

      <AdminUsersList initialUsers={users} currentUserId={session.user.id} />
    </div>
  )
}

'use client'

import { useState } from 'react'
import { signIn } from 'next-auth/react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import axios from 'axios'

type Role = 'jobseeker' | 'recruiter'

/* ── SVG icon components ─────────────────────────── */
function UserIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="8" r="5" />
      <path d="M20 21a8 8 0 0 0-16 0" />
    </svg>
  )
}

function MailIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <rect x="2" y="4" width="20" height="16" rx="3" />
      <path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7" />
    </svg>
  )
}

function LockIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <rect width="18" height="11" x="3" y="11" rx="2" ry="2" />
      <path d="M7 11V7a5 5 0 0 1 10 0v4" />
    </svg>
  )
}

function BuildingIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <rect x="4" y="2" width="16" height="20" rx="2" />
      <path d="M9 22v-4h6v4" />
      <path d="M8 6h.01" /><path d="M16 6h.01" />
      <path d="M8 10h.01" /><path d="M16 10h.01" />
      <path d="M8 14h.01" /><path d="M16 14h.01" />
    </svg>
  )
}

function MapPinIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20 10c0 4.993-5.539 10.193-7.399 11.799a1 1 0 0 1-1.202 0C9.539 20.193 4 14.993 4 10a8 8 0 0 1 16 0" />
      <circle cx="12" cy="10" r="3" />
    </svg>
  )
}

function EyeIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M2.062 12.348a1 1 0 0 1 0-.696 10.75 10.75 0 0 1 19.876 0 1 1 0 0 1 0 .696 10.75 10.75 0 0 1-19.876 0" />
      <circle cx="12" cy="12" r="3" />
    </svg>
  )
}

function EyeOffIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d="M10.733 5.076a10.744 10.744 0 0 1 11.205 6.575 1 1 0 0 1 0 .696 10.747 10.747 0 0 1-1.444 2.49" />
      <path d="M14.084 14.158a3 3 0 0 1-4.242-4.242" />
      <path d="M17.479 17.499a10.75 10.75 0 0 1-15.417-5.151 1 1 0 0 1 0-.696 10.75 10.75 0 0 1 4.446-5.143" />
      <path d="m2 2 20 20" />
    </svg>
  )
}

function CheckIcon({ className }: { className?: string }) {
  return (
    <svg className={className} width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <path d="M20 6 9 17l-5-5" />
    </svg>
  )
}

function GoogleIcon() {
  return (
    <svg width="18" height="18" viewBox="0 0 24 24">
      <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
      <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
      <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/>
      <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
    </svg>
  )
}

/* ── Benefits list ───────────────────────────────── */
const benefits = [
  { title: 'AI-Powered Matching', desc: 'Smart algorithms find the perfect fit for every role.' },
  { title: 'Instant Applications', desc: 'One-click apply with your saved profile and resume.' },
  { title: 'Real-time Messaging', desc: 'Chat directly with recruiters and candidates.' },
  { title: 'Analytics Dashboard', desc: 'Track performance with detailed insights and metrics.' },
]

export default function RegisterPage() {
  const router = useRouter()
  const [role, setRole] = useState<Role>('jobseeker')
  const [name, setName] = useState('')
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [showPass, setShowPass] = useState(false)
  const [companyName, setCompanyName] = useState('')
  const [companyLocation, setCompanyLocation] = useState('')
  const [industry, setIndustry] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setSuccess('')
    setLoading(true)

    try {
      const payload: Record<string, string> = { name, email, password, role }
      if (role === 'recruiter') {
        payload.companyName = companyName
        payload.companyLocation = companyLocation
        payload.industry = industry
      }

      const { data } = await axios.post('/api/auth/register', payload)
      setSuccess(data.message)
    } catch (err: any) {
      setError(err.response?.data?.error || 'Something went wrong')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen flex">

      {/* ── Left: Branding panel (hidden on mobile) ── */}
      <div className="hidden lg:flex lg:w-[48%] relative overflow-hidden">
        {/* Animated gradient */}
        <div
          className="absolute inset-0 animate-gradient-shift"
          style={{
            background: 'linear-gradient(135deg, #7c3aed 0%, #4f46e5 25%, #06b6d4 50%, #2563eb 75%, #7c3aed 100%)',
            backgroundSize: '300% 300%',
          }}
        />

        {/* Grid overlay */}
        <div
          className="absolute inset-0 opacity-[0.06]"
          style={{
            backgroundImage: `url("data:image/svg+xml,%3Csvg width='40' height='40' viewBox='0 0 40 40' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M0 0h40v40H0V0zm1 1h38v38H1V1z' fill='%23fff' fill-opacity='1' fill-rule='evenodd'/%3E%3C/svg%3E")`,
          }}
        />

        {/* Floating orbs */}
        <div className="absolute top-16 right-16 w-64 h-64 bg-white/10 rounded-full blur-3xl animate-float-delayed" />
        <div className="absolute bottom-24 left-12 w-52 h-52 bg-purple-300/15 rounded-full blur-3xl animate-float" />

        {/* Content */}
        <div className="relative z-10 flex flex-col justify-between w-full p-12 xl:p-16">
          {/* Logo */}
          <div>
            <Link href="/" className="flex items-center gap-2.5">
              <div className="w-10 h-10 bg-white/20 backdrop-blur-sm rounded-xl flex items-center justify-center">
                <span className="text-white font-bold text-lg">W</span>
              </div>
              <span className="text-2xl font-bold text-white tracking-tight">WorkHire</span>
            </Link>
          </div>

          {/* Hero text */}
          <div className="space-y-8">
            <div className="space-y-4">
              <h2 className="text-4xl xl:text-5xl font-bold text-white leading-[1.15] tracking-tight">
                Build your future<br />
                with WorkHire.
              </h2>
              <p className="text-white/70 text-lg leading-relaxed max-w-md">
                Whether you&apos;re hiring or looking — get started in under 2 minutes.
              </p>
            </div>

            {/* Benefits list */}
            <div className="space-y-4">
              {benefits.map((b) => (
                <div key={b.title} className="flex items-start gap-3">
                  <div className="mt-0.5 w-6 h-6 rounded-full bg-white/15 flex items-center justify-center flex-shrink-0">
                    <CheckIcon className="text-emerald-300" />
                  </div>
                  <div>
                    <p className="text-white font-medium text-sm">{b.title}</p>
                    <p className="text-white/55 text-xs mt-0.5">{b.desc}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Trust badges */}
          <div className="flex items-center gap-6">
            <div className="flex -space-x-2">
              {['#f59e0b', '#3b82f6', '#10b981', '#ef4444'].map((c, i) => (
                <div
                  key={i}
                  className="w-8 h-8 rounded-full border-2 border-white/30 flex items-center justify-center text-white text-[10px] font-bold"
                  style={{ background: c }}
                >
                  {String.fromCharCode(65 + i)}
                </div>
              ))}
            </div>
            <p className="text-white/70 text-sm">
              <span className="font-semibold text-white">2,500+</span> joined this month
            </p>
          </div>
        </div>
      </div>

      {/* ── Right: Form panel ──────────────────────── */}
      <div className="flex-1 flex flex-col bg-[#fafbff]">

        {/* Mobile header */}
        <nav className="lg:hidden flex justify-between items-center px-5 py-4 border-b border-border bg-white/80 backdrop-blur-sm sticky top-0 z-50">
          <Link href="/" className="flex items-center gap-2">
            <div className="w-8 h-8 bg-primary rounded-lg flex items-center justify-center">
              <span className="text-white font-bold text-sm">W</span>
            </div>
            <span className="text-lg font-bold text-foreground tracking-tight">WorkHire</span>
          </Link>
          <Link
            href="/login"
            className="text-sm font-semibold text-primary hover:text-primary-dark transition-colors"
          >
            Sign In
          </Link>
        </nav>

        {/* Form area */}
        <div className="flex-1 flex items-center justify-center px-5 py-8 lg:px-12">
          <div className="w-full max-w-[440px] animate-slide-up">

            {/* Header */}
            <div className="mb-7">
              <h1 className="text-3xl lg:text-[34px] font-bold text-foreground tracking-tight leading-tight">
                Create your account
              </h1>
              <p className="text-muted text-[15px] mt-2 leading-relaxed">
                {role === 'jobseeker'
                  ? 'Start your job search journey today.'
                  : 'Set up your company and start hiring.'}
              </p>
            </div>

            {/* Role switcher */}
            <div className="flex bg-[#f1f0fb] rounded-2xl p-1.5 mb-7">
              {(['jobseeker', 'recruiter'] as Role[]).map((r) => (
                <button
                  key={r}
                  id={`role-${r}`}
                  onClick={() => { setRole(r); setError(''); setSuccess('') }}
                  className={`flex-1 py-2.5 text-[13px] font-semibold rounded-xl transition-all duration-300
                    ${role === r
                      ? 'bg-white text-primary shadow-[0_2px_8px_rgba(79,70,229,0.12)]'
                      : 'text-muted hover:text-foreground'
                    }`}
                >
                  {r === 'jobseeker' ? 'Job Seeker' : 'Recruiter'}
                </button>
              ))}
            </div>

            {/* Messages */}
            {error && (
              <div className="mb-5 px-4 py-3 rounded-xl bg-error-bg border border-error/15 text-error text-sm flex items-center gap-2 animate-fade-in">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
                {error}
              </div>
            )}
            {success && (
              <div className="mb-5 px-4 py-3 rounded-xl bg-success-bg border border-success/15 text-success text-sm flex items-center gap-2 animate-fade-in">
                <CheckIcon className="w-4 h-4" />
                {success}
              </div>
            )}

            {/* Form */}
            <form onSubmit={handleSubmit} className="space-y-4">

              {/* Full Name */}
              <div className="space-y-1.5">
                <label htmlFor="reg-name" className="text-[13px] font-medium text-foreground">Full Name</label>
                <div className="relative group">
                  <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted group-focus-within:text-primary transition-colors duration-200">
                    <UserIcon />
                  </span>
                  <input
                    id="reg-name"
                    type="text"
                    required
                    placeholder="John Doe"
                    value={name}
                    onChange={e => setName(e.target.value)}
                    className="input-premium w-full pl-11 pr-4 py-3 bg-white border border-border rounded-xl text-sm placeholder:text-muted/50 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/10"
                  />
                </div>
              </div>

              {/* Email */}
              <div className="space-y-1.5">
                <label htmlFor="reg-email" className="text-[13px] font-medium text-foreground">Email</label>
                <div className="relative group">
                  <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted group-focus-within:text-primary transition-colors duration-200">
                    <MailIcon />
                  </span>
                  <input
                    id="reg-email"
                    type="email"
                    required
                    placeholder="you@company.com"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                    className="input-premium w-full pl-11 pr-4 py-3 bg-white border border-border rounded-xl text-sm placeholder:text-muted/50 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/10"
                  />
                </div>
              </div>

              {/* Password */}
              <div className="space-y-1.5">
                <label htmlFor="reg-password" className="text-[13px] font-medium text-foreground">Password</label>
                <div className="relative group">
                  <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted group-focus-within:text-primary transition-colors duration-200">
                    <LockIcon />
                  </span>
                  <input
                    id="reg-password"
                    type={showPass ? 'text' : 'password'}
                    required
                    minLength={6}
                    placeholder="Min. 6 characters"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="input-premium w-full pl-11 pr-12 py-3 bg-white border border-border rounded-xl text-sm placeholder:text-muted/50 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/10"
                  />
                  <button
                    type="button"
                    onClick={() => setShowPass(!showPass)}
                    className="absolute right-3.5 top-1/2 -translate-y-1/2 text-muted hover:text-foreground transition-colors"
                  >
                    {showPass ? <EyeOffIcon /> : <EyeIcon />}
                  </button>
                </div>
                {/* Password strength indicator */}
                {password.length > 0 && (
                  <div className="flex gap-1.5 mt-1">
                    {[1, 2, 3, 4].map((i) => (
                      <div
                        key={i}
                        className={`h-1 flex-1 rounded-full transition-all duration-300 ${
                          password.length >= i * 3
                            ? password.length >= 12 ? 'bg-emerald-500' : password.length >= 8 ? 'bg-amber-500' : 'bg-red-400'
                            : 'bg-border'
                        }`}
                      />
                    ))}
                  </div>
                )}
              </div>

              {/* Recruiter-only fields */}
              {role === 'recruiter' && (
                <div className="space-y-4 pt-2 border-t border-border animate-fade-in">
                  <p className="text-xs font-semibold text-muted uppercase tracking-wider pt-2">Company details</p>

                  {/* Company Name */}
                  <div className="space-y-1.5">
                    <label htmlFor="reg-company" className="text-[13px] font-medium text-foreground">Company Name</label>
                    <div className="relative group">
                      <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted group-focus-within:text-primary transition-colors duration-200">
                        <BuildingIcon />
                      </span>
                      <input
                        id="reg-company"
                        type="text"
                        required
                        placeholder="Acme Inc."
                        value={companyName}
                        onChange={e => setCompanyName(e.target.value)}
                        className="input-premium w-full pl-11 pr-4 py-3 bg-white border border-border rounded-xl text-sm placeholder:text-muted/50 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/10"
                      />
                    </div>
                  </div>

                  {/* Location + Industry row */}
                  <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1.5">
                      <label htmlFor="reg-location" className="text-[13px] font-medium text-foreground">Location</label>
                      <div className="relative group">
                        <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-muted group-focus-within:text-primary transition-colors duration-200">
                          <MapPinIcon className="w-4 h-4" />
                        </span>
                        <input
                          id="reg-location"
                          type="text"
                          placeholder="Mumbai"
                          value={companyLocation}
                          onChange={e => setCompanyLocation(e.target.value)}
                          className="input-premium w-full pl-10 pr-3 py-3 bg-white border border-border rounded-xl text-sm placeholder:text-muted/50 focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/10"
                        />
                      </div>
                    </div>
                    <div className="space-y-1.5">
                      <label htmlFor="reg-industry" className="text-[13px] font-medium text-foreground">Industry</label>
                      <select
                        id="reg-industry"
                        value={industry}
                        onChange={e => setIndustry(e.target.value)}
                        className="input-premium w-full px-3 py-3 bg-white border border-border rounded-xl text-sm text-foreground focus:outline-none focus:border-primary focus:ring-2 focus:ring-primary/10 appearance-none cursor-pointer"
                      >
                        <option value="">Select…</option>
                        <option value="Technology">Technology</option>
                        <option value="Finance">Finance</option>
                        <option value="Healthcare">Healthcare</option>
                        <option value="Education">Education</option>
                        <option value="E-Commerce">E-Commerce</option>
                        <option value="Manufacturing">Manufacturing</option>
                        <option value="Consulting">Consulting</option>
                        <option value="Other">Other</option>
                      </select>
                    </div>
                  </div>
                </div>
              )}

              {/* Terms */}
              <p className="text-[11px] text-muted leading-relaxed pt-1">
                By creating an account, you agree to our{' '}
                <Link href="#" className="text-primary hover:underline">Terms of Service</Link> and{' '}
                <Link href="#" className="text-primary hover:underline">Privacy Policy</Link>.
              </p>

              {/* Submit */}
              <button
                id="register-submit-btn"
                type="submit"
                disabled={loading || !!success}
                className="group w-full bg-primary text-white py-3 rounded-xl font-semibold text-sm
                  hover:bg-primary-dark active:scale-[0.98] transition-all duration-200
                  shadow-[0_4px_14px_rgba(79,70,229,0.25)] hover:shadow-[0_6px_20px_rgba(79,70,229,0.35)]
                  disabled:opacity-60 disabled:cursor-not-allowed
                  flex items-center justify-center gap-2"
              >
                {loading ? (
                  <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3"/>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                  </svg>
                ) : (
                  <>
                    {role === 'recruiter' ? 'Register Company' : 'Create Account'}
                    <svg className="w-4 h-4 group-hover:translate-x-0.5 transition-transform" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M5 12h14" /><path d="m12 5 7 7-7 7" />
                    </svg>
                  </>
                )}
              </button>
            </form>

            {/* Divider + Google */}
            <div className="flex items-center gap-4 my-6">
              <div className="h-px flex-1 bg-border" />
              <span className="text-xs text-muted font-medium uppercase tracking-wider">or</span>
              <div className="h-px flex-1 bg-border" />
            </div>

            <button
              id="google-register-btn"
              onClick={() => signIn('google', { callbackUrl: '/dashboard' })}
              className="w-full flex items-center justify-center gap-3 py-3 bg-white border border-border rounded-xl text-sm font-medium text-foreground hover:bg-surface hover:border-border-hover hover:shadow-sm transition-all duration-200 active:scale-[0.99]"
            >
              <GoogleIcon />
              Sign up with Google
            </button>

            {/* Login link */}
            <div className="mt-7 pt-5 border-t border-border text-center">
              <p className="text-sm text-muted">
                Already have an account?{' '}
                <Link href="/login" className="font-bold text-primary hover:text-primary-dark transition-colors">
                  Sign in
                </Link>
              </p>
            </div>

          </div>
        </div>

        {/* Footer */}
        <footer className="border-t border-border bg-white/60 backdrop-blur-sm">
          <div className="flex flex-col sm:flex-row justify-between items-center px-5 lg:px-12 py-4 gap-2">
            <span className="text-xs text-muted">© 2026 WorkHire. All rights reserved.</span>
            <div className="flex gap-5">
              {['Privacy', 'Terms', 'Help'].map(l => (
                <span key={l} className="text-xs text-muted hover:text-primary cursor-pointer transition-colors">{l}</span>
              ))}
            </div>
          </div>
        </footer>
      </div>
    </div>
  )
}

// 📄 PAGE: Manage Applicants
// 🌐 URL: /company/dashboard/applicants
// 👤 WHO: Recruiters only

import { getServerSession } from 'next-auth'
import { authOptions } from '@/utils/auth'
import connectDB from '@/lib/db'
import Company from '@/models/Company'
import Application from '@/models/Application'
import User from '@/models/User'
import Job from '@/models/Job'
import ApplicantActions from '@/components/applications/ApplicantActions'

interface Props {
  searchParams: { jobId?: string; status?: string }
}

export default async function ApplicantsPage({ searchParams }: Props) {
  const session = await getServerSession(authOptions)
  await connectDB()

  const company = await Company.findOne({ ownerId: session?.user.id }).lean() as any

  const filter: any = { companyId: company._id }
  if (searchParams.jobId)  filter.jobId  = searchParams.jobId
  if (searchParams.status) filter.status = searchParams.status

  const applications = await Application.find(filter)
    .populate('seekerId', 'name email avatar skills resume bio location')
    .populate('jobId',    'title location type')
    .sort({ createdAt: -1 })
    .lean()

  const statusColors: Record<string, string> = {
    applied:   'bg-[#e5eeff] text-[#4648d4]',
    reviewed:  'bg-blue-50 text-blue-600',
    interview: 'bg-amber-50 text-amber-700',
    hired:     'bg-green-50 text-green-700',
    rejected:  'bg-[#ffdad6] text-[#93000a]',
  }

  const counts = {
    all:       applications.length,
    applied:   applications.filter((a: any) => a.status === 'applied').length,
    reviewed:  applications.filter((a: any) => a.status === 'reviewed').length,
    interview: applications.filter((a: any) => a.status === 'interview').length,
    hired:     applications.filter((a: any) => a.status === 'hired').length,
    rejected:  applications.filter((a: any) => a.status === 'rejected').length,
  }

  return (
    <div className="space-y-5">

      {/* Header */}
      <div>
        <h1 className="text-xl font-bold text-[#0b1c30]">Applicants</h1>
        <p className="text-sm text-[#777587]">{applications.length} total applications</p>
      </div>

      {/* Status filter tabs */}
      <div className="flex gap-2 flex-wrap">
        {Object.entries(counts).map(([status, count]) => (
          <a
            key={status}
            href={status === 'all'
              ? '/company/dashboard/applicants'
              : `/company/dashboard/applicants?status=${status}`
            }
            className={`px-3 py-1.5 rounded-xl text-xs font-semibold transition-all capitalize
              ${(!searchParams.status && status === 'all') || searchParams.status === status
                ? 'bg-[#3525cd] text-white'
                : 'bg-white border border-[#c7c4d8] text-[#464555] hover:border-[#3525cd]/40 hover:text-[#3525cd]'
              }`}
          >
            {status} ({count})
          </a>
        ))}
      </div>

      {/* List */}
      {applications.length === 0 ? (
        <div className="bg-white rounded-xl border border-[#c7c4d8] p-16 text-center">
          <p className="text-5xl mb-4">👥</p>
          <h2 className="text-lg font-semibold text-[#0b1c30] mb-2">No applicants yet</h2>
          <p className="text-sm text-[#777587]">Applications will appear here once candidates apply</p>
        </div>
      ) : (
        <div className="space-y-3">
          {applications.map((app: any) => (
            <div key={app._id.toString()} className="bg-white rounded-xl border border-[#c7c4d8] p-5 hover:border-[#3525cd]/30 transition-colors">
              <div className="flex items-start gap-4">

                {/* Avatar */}
                <div className="w-12 h-12 rounded-xl bg-[#e2dfff] flex items-center justify-center text-[#3525cd] font-bold text-lg shrink-0">
                  {app.seekerId?.name?.charAt(0) || '?'}
                </div>

                {/* Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <h3 className="font-semibold text-[#0b1c30]">
                        {app.seekerId?.name || 'Unknown'}
                      </h3>
                      <p className="text-xs text-[#777587]">
                        {app.seekerId?.email} ·{' '}
                        {app.jobId?.title}
                      </p>
                    </div>
                    <span className={`text-xs font-medium px-3 py-1 rounded-full capitalize shrink-0 ${statusColors[app.status]}`}>
                      {app.status}
                    </span>
                  </div>

                  {/* Skills */}
                  {app.seekerId?.skills?.length > 0 && (
                    <div className="flex flex-wrap gap-1.5 mt-2">
                      {app.seekerId.skills.slice(0, 5).map((skill: string) => (
                        <span key={skill} className="px-2 py-0.5 rounded-full bg-[#eff4ff] text-[#464555] text-xs">
                          {skill}
                        </span>
                      ))}
                    </div>
                  )}

                  {/* Cover letter */}
                  {app.coverLetter && (
                    <p className="text-xs text-[#464555] mt-2 line-clamp-2 bg-[#f8f9ff] rounded-lg p-2">
                      "{app.coverLetter}"
                    </p>
                  )}

                  {/* Actions row */}
                  <div className="flex items-center gap-2 mt-3 flex-wrap">
                    {/* View resume */}
                    {app.seekerId?.resume && (
                      <a
                        href={app.seekerId.resume}
                        target="_blank"
                        rel="noreferrer"
                        className="text-xs px-3 py-1.5 rounded-xl bg-[#e2dfff] text-[#3525cd] font-semibold hover:bg-[#3525cd] hover:text-white transition-all"
                      >
                        📄 View Resume
                      </a>
                    )}

                    {/* Applied date */}
                    <span className="text-xs text-[#777587]">
                      Applied {new Date(app.createdAt).toLocaleDateString('en-IN', {
                        day: 'numeric', month: 'short', year: 'numeric'
                      })}
                    </span>

                    {/* Status update + message — client component */}
                    <ApplicantActions
                      applicationId={app._id.toString()}
                      currentStatus={app.status}
                      seekerId={app.seekerId?._id?.toString()}
                      seekerName={app.seekerId?.name}
                    />
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// 📄 PAGE: Billing & Subscription
// 🌐 URL: /company/dashboard/billing
// 👤 WHO: Recruiters only

'use client'

import { useState } from 'react'
import axios from 'axios'

const plans = [
  {
    key:   'free',
    name:  'Free',
    price: '₹0',
    period: '/month',
    features: [
      '3 job posts',
      'Basic applicant tracking',
      'Email notifications',
    ],
    color:  'border-[#c7c4d8]',
    badge:  '',
  },
  {
    key:   'pro',
    name:  'Pro',
    price: '₹999',
    period: '/month',
    features: [
      'Unlimited job posts',
      'Advanced analytics',
      'Real-time chat',
      'Priority listing',
      'AI candidate ranking',
    ],
    color: 'border-[#3525cd]',
    badge: '⭐ Most Popular',
  },
  {
    key:   'enterprise',
    name:  'Enterprise',
    price: '₹2,999',
    period: '/month',
    features: [
      'Everything in Pro',
      'Dedicated support',
      'Custom integrations',
      'Team access',
      'API access',
    ],
    color: 'border-[#4648d4]',
    badge: '🏢 For Teams',
  },
]

export default function BillingPage() {
  const [loading, setLoading] = useState<string | null>(null)
  const [currentPlan, setCurrentPlan] = useState('free')
  const [error, setError] = useState('')

  async function handleUpgrade(plan: string) {
    if (plan === 'free') return
    setError('')
    setLoading(plan)
    try {
      const { data } = await axios.post('/api/razorpay/create-order', { plan })

      // Load Razorpay script
      const script = document.createElement('script')
      script.src = 'https://checkout.razorpay.com/v1/checkout.js'
      document.body.appendChild(script)

      script.onload = () => {
        const options = {
          key:         process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID,
          amount:      data.amount,
          currency:    'INR',
          name:        'WorkHire',
          description: `${plan.charAt(0).toUpperCase() + plan.slice(1)} Plan`,
          order_id:    data.orderId,
          handler:     async (response: any) => {
            try {
              await axios.post('/api/razorpay/verify', {
                razorpay_order_id:   response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature:  response.razorpay_signature,
                plan,
              })
              setCurrentPlan(plan)
              window.location.reload()
            } catch {
              setError('Payment verification failed. Contact support.')
            }
          },
          prefill:  { name: '', email: '' },
          theme:    { color: '#3525cd' },
        }

        const rzp = new (window as any).Razorpay(options)
        rzp.open()
      }
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to initiate payment')
    } finally {
      setLoading(null)
    }
  }

  return (
    <div className="space-y-6 max-w-4xl">

      {/* Header */}
      <div>
        <h1 className="text-xl font-bold text-[#0b1c30]">Billing & Plans</h1>
        <p className="text-sm text-[#777587]">Choose a plan that works for your hiring needs</p>
      </div>

      {/* Current plan */}
      <div className="bg-[#eff4ff] border border-[#3525cd]/20 rounded-xl p-5 flex items-center justify-between">
        <div>
          <p className="text-sm font-semibold text-[#0b1c30]">
            Current Plan: <span className="text-[#3525cd] capitalize">{currentPlan}</span>
          </p>
          <p className="text-xs text-[#777587] mt-0.5">
            {currentPlan === 'free'
              ? 'Upgrade to unlock unlimited jobs and more features'
              : 'Your subscription is active'}
          </p>
        </div>
        {currentPlan !== 'free' && (
          <button className="text-xs px-3 py-1.5 rounded-xl border border-[#c7c4d8] text-[#464555] hover:bg-white transition-colors">
            Manage Subscription
          </button>
        )}
      </div>

      {error && (
        <div className="px-4 py-3 rounded-xl bg-[#ffdad6] text-[#93000a] text-sm">{error}</div>
      )}

      {/* Plans */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {plans.map(plan => {
          const isCurrent = currentPlan === plan.key
          return (
            <div
              key={plan.key}
              className={`bg-white rounded-xl border-2 p-6 flex flex-col relative ${plan.color} ${
                plan.key === 'pro' ? 'shadow-[0px_4px_20px_rgba(53,37,205,0.12)]' : ''
              }`}
            >
              {plan.badge && (
                <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-[#3525cd] text-white text-xs font-semibold px-3 py-1 rounded-full whitespace-nowrap">
                  {plan.badge}
                </div>
              )}

              <div className="mb-4">
                <h3 className="font-bold text-lg text-[#0b1c30]">{plan.name}</h3>
                <div className="flex items-end gap-1 mt-1">
                  <span className="text-3xl font-bold text-[#3525cd]">{plan.price}</span>
                  <span className="text-sm text-[#777587] mb-1">{plan.period}</span>
                </div>
              </div>

              <ul className="space-y-2 flex-1 mb-6">
                {plan.features.map(f => (
                  <li key={f} className="flex items-start gap-2 text-sm text-[#464555]">
                    <span className="text-[#3525cd] mt-0.5 shrink-0">✓</span>
                    {f}
                  </li>
                ))}
              </ul>

              <button
                onClick={() => handleUpgrade(plan.key)}
                disabled={isCurrent || loading === plan.key || plan.key === 'free'}
                className={`w-full py-2.5 rounded-xl text-sm font-semibold transition-all
                  ${isCurrent
                    ? 'bg-green-50 text-green-600 cursor-default'
                    : plan.key === 'free'
                    ? 'bg-[#f8f9ff] text-[#777587] cursor-default'
                    : 'bg-[#3525cd] text-white hover:opacity-90 active:scale-[0.98] shadow-[0px_4px_12px_rgba(79,70,229,0.2)]'
                  } disabled:opacity-60 flex items-center justify-center gap-2`}
              >
                {loading === plan.key ? (
                  <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                  </svg>
                ) : isCurrent ? '✅ Current Plan' :
                   plan.key === 'free' ? 'Free Forever' : `Upgrade to ${plan.name}`}
              </button>
            </div>
          )
        })}
      </div>

      {/* FAQ */}
      <div className="bg-white rounded-xl border border-[#c7c4d8] p-6 space-y-4">
        <h2 className="font-semibold text-[#0b1c30]">Frequently Asked Questions</h2>
        {[
          ['Can I cancel anytime?', 'Yes, you can cancel your subscription anytime. You will retain access until the end of your billing period.'],
          ['What payment methods are accepted?', 'We accept credit/debit cards, UPI, net banking, and popular international and local payment methods via Razorpay.'],
          ['Is there a free trial?', 'The Free plan is available forever with limited features. No credit card required.'],
        ].map(([q, a]) => (
          <div key={q} className="border-b border-[#c7c4d8] pb-4 last:border-0 last:pb-0">
            <p className="text-sm font-semibold text-[#0b1c30] mb-1">{q}</p>
            <p className="text-xs text-[#777587]">{a}</p>
          </div>
        ))}
      </div>

    </div>
  )
}

// 📄 PAGE: Post New Job
// 🌐 URL: /company/dashboard/jobs/new
// 👤 WHO: Recruiters only

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import axios from 'axios'

export default function NewJobPage() {
  const router = useRouter()
  const [loading, setLoading] = useState(false)
  const [error, setError]     = useState('')

  const [form, setForm] = useState({
    title:       '',
    description: '',
    location:    '',
    type:        'full-time',
    experience:  'fresher',
    salaryMin:   '',
    salaryMax:   '',
    skills:      '',
    requirements:'',
    deadline:    '',
    status:      'active',
  })

  const update = (f: string, v: string) => setForm(p => ({ ...p, [f]: v }))

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')
    setLoading(true)

    try {
      await axios.post('/api/jobs', {
        title:        form.title,
        description:  form.description,
        location:     form.location,
        type:         form.type,
        experience:   form.experience,
        salary: {
          min:      form.salaryMin ? Number(form.salaryMin) : undefined,
          max:      form.salaryMax ? Number(form.salaryMax) : undefined,
          currency: 'INR',
        },
        skills:        form.skills.split(',').map(s => s.trim()).filter(Boolean),
        requirements:  form.requirements.split('\n').filter(Boolean),
        deadline:      form.deadline || undefined,
        status:        form.status,
      })
      router.push('/company/dashboard/jobs')
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to post job')
    } finally {
      setLoading(false)
    }
  }

  const inputCls = "w-full px-4 py-2.5 bg-[#f8f9ff] border border-[#c7c4d8] rounded-xl text-sm focus:outline-none focus:border-[#3525cd] focus:ring-1 focus:ring-[#3525cd] transition-all"

  return (
    <div className="max-w-3xl space-y-5">

      {/* Header */}
      <div>
        <h1 className="text-xl font-bold text-[#0b1c30]">Post New Job</h1>
        <p className="text-sm text-[#777587]">Fill in the details to attract the right candidates</p>
      </div>

      {error && (
        <div className="px-4 py-3 rounded-xl bg-[#ffdad6] text-[#93000a] text-sm">{error}</div>
      )}

      <form onSubmit={handleSubmit} className="space-y-5">

        {/* Basic info */}
        <div className="bg-white rounded-xl border border-[#c7c4d8] p-6 space-y-4">
          <h2 className="font-semibold text-[#0b1c30]">Job Details</h2>

          <div>
            <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Job Title *</label>
            <input
              type="text" required
              value={form.title}
              onChange={e => update('title', e.target.value)}
              className={inputCls}
              placeholder="e.g. Senior React Developer"
            />
          </div>

          <div>
            <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Job Description *</label>
            <textarea
              rows={5} required
              value={form.description}
              onChange={e => update('description', e.target.value)}
              className={inputCls + ' resize-none'}
              placeholder="Describe the role, responsibilities, and what you're looking for..."
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Location</label>
              <input
                type="text"
                value={form.location}
                onChange={e => update('location', e.target.value)}
                className={inputCls}
                placeholder="e.g. Bangalore / Remote"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Job Type</label>
              <select
                value={form.type}
                onChange={e => update('type', e.target.value)}
                className={inputCls}
              >
                {['full-time', 'part-time', 'remote', 'internship', 'contract'].map(t => (
                  <option key={t} value={t} className="capitalize">{t}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Experience Level</label>
              <select
                value={form.experience}
                onChange={e => update('experience', e.target.value)}
                className={inputCls}
              >
                {[
                  ['fresher', 'Fresher'],
                  ['1-2', '1–2 years'],
                  ['2-5', '2–5 years'],
                  ['5-10', '5–10 years'],
                  ['10+', '10+ years'],
                ].map(([v, l]) => (
                  <option key={v} value={v}>{l}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Application Deadline</label>
              <input
                type="date"
                value={form.deadline}
                onChange={e => update('deadline', e.target.value)}
                className={inputCls}
              />
            </div>
          </div>
        </div>

        {/* Salary */}
        <div className="bg-white rounded-xl border border-[#c7c4d8] p-6 space-y-4">
          <h2 className="font-semibold text-[#0b1c30]">Salary Range (INR)</h2>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Minimum (₹)</label>
              <input
                type="number"
                value={form.salaryMin}
                onChange={e => update('salaryMin', e.target.value)}
                className={inputCls}
                placeholder="e.g. 500000"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">Maximum (₹)</label>
              <input
                type="number"
                value={form.salaryMax}
                onChange={e => update('salaryMax', e.target.value)}
                className={inputCls}
                placeholder="e.g. 1000000"
              />
            </div>
          </div>
        </div>

        {/* Skills + Requirements */}
        <div className="bg-white rounded-xl border border-[#c7c4d8] p-6 space-y-4">
          <h2 className="font-semibold text-[#0b1c30]">Skills & Requirements</h2>

          <div>
            <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">
              Required Skills <span className="text-[#777587]">(comma separated)</span>
            </label>
            <input
              type="text"
              value={form.skills}
              onChange={e => update('skills', e.target.value)}
              className={inputCls}
              placeholder="React, Node.js, TypeScript, MongoDB..."
            />
            {form.skills && (
              <div className="flex flex-wrap gap-1.5 mt-2">
                {form.skills.split(',').map(s => s.trim()).filter(Boolean).map(skill => (
                  <span key={skill} className="px-2 py-0.5 rounded-full bg-[#e2dfff] text-[#3525cd] text-xs">
                    {skill}
                  </span>
                ))}
              </div>
            )}
          </div>

          <div>
            <label className="block text-xs font-medium text-[#464555] mb-1.5 ml-1">
              Requirements <span className="text-[#777587]">(one per line)</span>
            </label>
            <textarea
              rows={4}
              value={form.requirements}
              onChange={e => update('requirements', e.target.value)}
              className={inputCls + ' resize-none'}
              placeholder="3+ years of React experience&#10;Strong knowledge of TypeScript&#10;Experience with RESTful APIs"
            />
          </div>
        </div>

        {/* Publish options */}
        <div className="bg-white rounded-xl border border-[#c7c4d8] p-6">
          <h2 className="font-semibold text-[#0b1c30] mb-3">Publish Options</h2>
          <div className="flex gap-3">
            {[
              { value: 'active', label: '🚀 Publish Now',  desc: 'Visible to job seekers immediately' },
              { value: 'draft',  label: '📝 Save as Draft', desc: 'Save and publish later' },
            ].map(({ value, label, desc }) => (
              <label
                key={value}
                className={`flex-1 p-3 rounded-xl border cursor-pointer transition-all ${
                  form.status === value
                    ? 'border-[#3525cd] bg-[#eff4ff]'
                    : 'border-[#c7c4d8] hover:border-[#3525cd]/40'
                }`}
              >
                <input
                  type="radio"
                  name="status"
                  value={value}
                  checked={form.status === value}
                  onChange={e => update('status', e.target.value)}
                  className="sr-only"
                />
                <p className="text-sm font-semibold text-[#0b1c30]">{label}</p>
                <p className="text-xs text-[#777587] mt-0.5">{desc}</p>
              </label>
            ))}
          </div>
        </div>

        {/* Submit */}
        <div className="flex gap-3 justify-end">
          <button
            type="button"
            onClick={() => router.back()}
            className="px-6 py-2.5 rounded-xl border border-[#c7c4d8] text-sm font-semibold text-[#464555] hover:bg-[#eff4ff] transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className="px-8 py-2.5 rounded-xl bg-[#3525cd] text-white text-sm font-semibold hover:opacity-90 active:scale-[0.98] disabled:opacity-60 flex items-center gap-2 transition-all shadow-[0px_4px_12px_rgba(79,70,229,0.2)]"
          >
            {loading ? (
              <>
                <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                </svg>
                Posting...
              </>
            ) : form.status === 'active' ? '🚀 Publish Job' : '📝 Save Draft'}
          </button>
        </div>

      </form>
    </div>
  )
}

// 📄 LAYOUT: Recruiter Dashboard
// 🌐 WRAPS: /company/dashboard/*
// 👤 WHO: Recruiters only (protected by middleware)

import { getServerSession } from 'next-auth'
import { authOptions } from '@/utils/auth'
import { redirect } from 'next/navigation'
import RecruiterSidebar from '@/components/dashboard/RecruiterSidebar'
import connectDB from '@/lib/db'
import Company from '@/models/Company'
import NotificationBell from '@/components/dashboard/NotificationBell'
import { CheckCircle2, Clock, AlertTriangle } from 'lucide-react'

export default async function RecruiterLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const session = await getServerSession(authOptions)

  if (!session) redirect('/login')
  if (session.user.role === 'admin') redirect('/admin')
  if (session.user.role === 'jobseeker') redirect('/dashboard')
  if (session.user.role !== 'recruiter') redirect('/login')

  await connectDB()

  // Get company info
  const company = await Company.findOne({ ownerId: session.user.id }).lean() as any

  // Not verified or not approved yet
  if (!company) redirect('/login')

  return (
    <div className="min-h-screen bg-[#fafbff] flex font-sans selection:bg-primary/20 selection:text-primary">

      <RecruiterSidebar user={session.user} company={company} />

      <div className="flex-1 flex flex-col min-h-screen ml-0 md:ml-64 relative">

        {/* Top bar */}
        <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-[#e2e8f0] pl-16 pr-6 md:px-6 py-4 flex items-center justify-between">
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-sm font-bold text-foreground">
                {company.name}
              </h1>
              <span className={`inline-flex items-center gap-1 text-[10px] font-extrabold px-2.5 py-0.5 rounded-full border tracking-wide uppercase
                ${company.isAdminApproved
                  ? 'bg-emerald-50 text-emerald-600 border-emerald-200'
                  : 'bg-amber-50 text-amber-600 border-amber-200'
                }`}>
                {company.isAdminApproved ? (
                  <>
                    <CheckCircle2 className="w-2.5 h-2.5" />
                    Approved
                  </>
                ) : (
                  <>
                    <Clock className="w-2.5 h-2.5" />
                    Pending
                  </>
                )}
              </span>
            </div>

            <p className="text-[10px] text-muted font-bold tracking-wide mt-0.5 uppercase">
              Recruiter Hub · Plan:{' '}
              <span className="text-primary font-extrabold">
                {company.subscription?.plan || 'free'}
              </span>
            </p>
          </div>

          <div className="flex items-center gap-4">
            {/* Notification button */}
            <NotificationBell />

            {/* Recruiter Avatar */}
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-primary to-primary-dark flex items-center justify-center text-white text-sm font-bold shadow-md shadow-primary/10">
              {session.user.name?.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        {/* Pending approval banner */}
        {!company.isAdminApproved && (
          <div className="bg-amber-500/10 border-b border-amber-500/20 px-6 py-3.5 text-xs text-amber-700 font-semibold flex items-center gap-2.5">
            <AlertTriangle className="w-4.5 h-4.5 text-amber-600 shrink-0" />
            <span>Your company is pending admin approval. You can complete setting up your profile but cannot publish new job listings yet.</span>
          </div>
        )}

        <main className="flex-1 p-6 md:p-8 max-w-6xl w-full mx-auto">
          {children}
        </main>

      </div>
    </div>
  )
}

// 📄 PAGE: Job Detail + Apply
