// 📡 API: Get, Update, Delete single job
// 🌐 GET/PUT/DELETE /api/jobs/[id]

import { NextRequest, NextResponse } from 'next/server'
import { getServerSession } from 'next-auth'
import { authOptions } from '@/utils/auth'
import connectDB from '@/lib/db'
import Job from '@/models/Job'
import Company from '@/models/Company'

interface Params { params: Promise<{ id: string }> }

export async function GET(_: NextRequest, { params }: Params) {
  try {
    await connectDB()
    const job = await Job.findById((await params).id)
      .populate('companyId', 'name logo location industry website description')
      .lean()

    if (!job) {
      return NextResponse.json({ error: 'Job not found' }, { status: 404 })
    }
    return NextResponse.json({ job })
  } catch (error) {
    return NextResponse.json({ error: 'Something went wrong' }, { status: 500 })
  }
}

export async function PUT(req: NextRequest, { params }: Params) {
  try {
    const session = await getServerSession(authOptions)
    if (!session || session.user.role !== 'recruiter') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    await connectDB()

    const company = await Company.findOne({ ownerId: session.user.id })
    if (!company) {
      return NextResponse.json({ error: 'Company not found' }, { status: 404 })
    }
    if (!company.isAdminApproved) {
      return NextResponse.json({ error: 'Company not approved yet' }, { status: 403 })
    }

    const job     = await Job.findOne({ _id: (await params).id, companyId: company._id })

    if (!job) {
      return NextResponse.json({ error: 'Job not found' }, { status: 404 })
    }

    const body = await req.json()
    const updated = await Job.findByIdAndUpdate((await params).id, body, { new: true })

    return NextResponse.json({ message: 'Job updated!', job: updated })
  } catch (error) {
    return NextResponse.json({ error: 'Something went wrong' }, { status: 500 })
  }
}

export async function DELETE(_: NextRequest, { params }: Params) {
  try {
    const session = await getServerSession(authOptions)
    if (!session || session.user.role !== 'recruiter') {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    await connectDB()

    const company = await Company.findOne({ ownerId: session.user.id })
    const job     = await Job.findOne({ _id: (await params).id, companyId: company?._id })

    if (!job) {
      return NextResponse.json({ error: 'Job not found' }, { status: 404 })
    }

    await Job.findByIdAndDelete((await params).id)
    return NextResponse.json({ message: 'Job deleted!' })
  } catch (error) {
    return NextResponse.json({ error: 'Something went wrong' }, { status: 500 })
  }
}

// 📡 API: Get all jobs + Post new job
// 🌐 GET  /api/jobs
// 🌐 POST /api/jobs

import { NextRequest, NextResponse } from 'next/server'
import { getServerSession } from 'next-auth'
import { authOptions } from '@/utils/auth'
import connectDB from '@/lib/db'
import Job from '@/models/Job'
import Company from '@/models/Company'
import { PLAN_LIMITS } from '@/types'

// GET all active jobs (public)
export async function GET(req: NextRequest) {
  try {
    await connectDB()
    const { searchParams } = new URL(req.url)

    const approvedCompanies = await Company.find({ isAdminApproved: true }).select('_id').lean()
    const approvedCompanyIds = approvedCompanies.map(c => c._id)

    const filter: any = { status: 'active', companyId: { $in: approvedCompanyIds } }
    if (searchParams.get('type'))     filter.type     = searchParams.get('type')
    if (searchParams.get('location')) filter.location = new RegExp(searchParams.get('location')!, 'i')
    if (searchParams.get('search'))   filter.title    = new RegExp(searchParams.get('search')!, 'i')

    const page  = Number(searchParams.get('page')  || 1)
    const limit = Number(searchParams.get('limit') || 10)
    const skip  = (page - 1) * limit

    const [jobs, total] = await Promise.all([
      Job.find(filter)
        .populate('companyId', 'name logo location industry')
        .sort({ createdAt: -1 })
        .skip(skip)
        .limit(limit)
        .lean(),
      Job.countDocuments(filter),
    ])

    return NextResponse.json({
      jobs,
      total,
      pages: Math.ceil(total / limit),
      page,
    })

  } catch (error) {
    console.error('Get jobs error:', error)
    return NextResponse.json({ error: 'Something went wrong' }, { status: 500 })
  }
}

// POST create job (recruiter only)
export async function POST(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions)
    if (!session) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }
    if (session.user.role !== 'recruiter') {
      return NextResponse.json({ error: 'Recruiters only' }, { status: 403 })
    }

    await connectDB()

    const company = await Company.findOne({ ownerId: session.user.id })
    if (!company) {
      return NextResponse.json({ error: 'Company not found' }, { status: 404 })
    }
    if (!company.isAdminApproved) {
      return NextResponse.json({ error: 'Company not approved yet' }, { status: 403 })
    }

    // Check plan limit
    const plan      = company.subscription?.plan || 'free'
    const jobLimit  = PLAN_LIMITS[plan as keyof typeof PLAN_LIMITS]?.jobLimit
    const jobCount  = await Job.countDocuments({ companyId: company._id })

    if (jobLimit !== Infinity && jobCount >= jobLimit) {
      return NextResponse.json(
        { error: `Job limit reached for ${plan} plan. Please upgrade.` },
        { status: 403 }
      )
    }

    const body = await req.json()
    const {
      title, description, location, type,
      experience, salary, skills, requirements,
      deadline, status,
    } = body

    if (!title || !description) {
      return NextResponse.json(
        { error: 'Title and description are required' },
        { status: 400 }
      )
    }

    const job = await Job.create({
      companyId: company._id,
      title, description, location, type,
      experience, salary, skills, requirements,
      deadline, status: status || 'active',
    })

    return NextResponse.json({ message: 'Job posted!', job }, { status: 201 })

  } catch (error) {
    console.error('Post job error:', error)
    return NextResponse.json({ error: 'Something went wrong' }, { status: 500 })
  }
}

// 📡 API: Get all conversations
// 🌐 GET /api/messages/conversations

import { NextRequest, NextResponse } from 'next/server'
import { getServerSession } from 'next-auth'
import { authOptions } from '@/utils/auth'
import connectDB from '@/lib/db'
import Message from '@/models/Message'
import Application from '@/models/Application'
import User from '@/models/User'
import Job from '@/models/Job'
import Company from '@/models/Company'
import mongoose from 'mongoose'

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions)
    if (!session) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    await connectDB()

    // Get all messages involving this user
    const messages = await Message.find({
      $or: [
        { senderId:   session.user.id },
        { receiverId: session.user.id },
      ],
    })
    .sort({ createdAt: -1 })
    .lean()

    // Group by applicationId
    const convMap = new Map<string, any>()

    for (const msg of messages) {
      const appId    = msg.applicationId?.toString() || 'direct'
      const otherUserId = msg.senderId.toString() === session.user.id
        ? msg.receiverId.toString()
        : msg.senderId.toString()

      if (!convMap.has(appId)) {
        convMap.set(appId, {
          applicationId: appId,
          userId:        otherUserId,
          lastMessage:   msg.content,
          unread:        0,
          createdAt:     msg.createdAt,
        })
      }

      // Count unread
      if (
        msg.receiverId.toString() === session.user.id &&
        !msg.read
      ) {
        convMap.get(appId).unread++
      }
    }

    // Check if query params specify a user & application to start/auto-open a new conversation
    const { searchParams } = new URL(req.url)
    const queryUserId = searchParams.get('userId')
    const queryAppId = searchParams.get('applicationId') || 'direct'

    if (
      queryUserId &&
      mongoose.Types.ObjectId.isValid(queryUserId) &&
      queryUserId !== session.user.id &&
      !convMap.has(queryAppId)
    ) {
      let canCreate = false
      if (queryAppId !== 'direct' && mongoose.Types.ObjectId.isValid(queryAppId)) {
        const app = await Application.findById(queryAppId).select('seekerId companyId').lean()
        if (app) {
          const company = await Company.findById(app.companyId).select('ownerId').lean()
          const seekerId = app.seekerId.toString()
          const recruiterId = company?.ownerId?.toString() || ''
          const me = session.user.id
          canCreate =
            (me === seekerId && queryUserId === recruiterId) ||
            (me === recruiterId && queryUserId === seekerId)
        }
      }

      if (canCreate) {
        convMap.set(queryAppId, {
          applicationId: queryAppId,
          userId:        queryUserId,
          lastMessage:   '',
          unread:        0,
          createdAt:     new Date(),
        })
      }
    }

    // Enrich with user + job info
    const conversations = await Promise.all(
      Array.from(convMap.values()).map(async conv => {
        const otherUser = await User.findById(conv.userId)
          .select('name avatar')
          .lean() as any

        let jobTitle    = ''
        let companyName = ''

        if (conv.applicationId !== 'direct') {
          const app = await Application.findById(conv.applicationId)
            .populate('jobId', 'title')
            .populate('companyId', 'name')
            .lean() as any

          jobTitle    = app?.jobId?.title    || ''
          companyName = app?.companyId?.name || ''
        }

        return {
          ...conv,
          name:        otherUser?.name || 'Unknown',
          avatar:      otherUser?.avatar || '',
          jobTitle,
          companyName,
        }
      })
    )

    return NextResponse.json({
      conversations,
      currentUserId: session.user.id,
    })

  } catch (error) {
    console.error('Conversations error:', error)
    return NextResponse.json({ error: 'Something went wrong' }, { status: 500 })
  }
}

import { MetadataRoute } from 'next'
import connectDB from '@/lib/db'
import Job from '@/models/Job'

export default async function sitemap(): Promise<MetadataRoute.Sitemap> {
  try {
    await connectDB()

    // Fetch all active jobs to populate in sitemap
    const jobs = await Job.find({ status: 'active' })
      .select('_id updatedAt')
      .lean() as any[]

    const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'https://workhire.com'

    const jobEntries = jobs.map(job => ({
      url: `${baseUrl}/jobs/${job._id.toString()}`,
      lastModified: job.updatedAt ? new Date(job.updatedAt) : new Date(),
      changeFrequency: 'weekly' as const,
      priority: 0.7,
    }))

    const staticEntries = [
      {
        url: `${baseUrl}`,
        lastModified: new Date(),
        changeFrequency: 'daily' as const,
        priority: 1.0,
      },
      {
        url: `${baseUrl}/jobs`,
        lastModified: new Date(),
        changeFrequency: 'daily' as const,
        priority: 0.9,
      },
      {
        url: `${baseUrl}/login`,
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.5,
      },
      {
        url: `${baseUrl}/register`,
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.5,
      },
      {
        url: `${baseUrl}/about`,
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.6,
      },
      {
        url: `${baseUrl}/contact`,
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.6,
      },
      {
        url: `${baseUrl}/privacy`,
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.4,
      },
      {
        url: `${baseUrl}/terms`,
        lastModified: new Date(),
        changeFrequency: 'monthly' as const,
        priority: 0.4,
      },
    ]

    return [...staticEntries, ...jobEntries]
  } catch (error) {
    console.error('Sitemap generation error:', error)
    // Return static entries as fallback
    const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'https://workhire.com'
    return [
      {
        url: `${baseUrl}`,
        lastModified: new Date(),
        changeFrequency: 'daily' as const,
        priority: 1.0,
      },
      {
        url: `${baseUrl}/jobs`,
        lastModified: new Date(),
        changeFrequency: 'daily' as const,
        priority: 0.9,
      },
    ]
  }
}

