          transform: `translate3d(-${currentIndex * 100}%, 0, 0)`,
        }}
      >
        {testimonials.map(({ name, role, company, avatar, color, quote }) => (
          <div key={name} className="w-full shrink-0 px-4">
            <div className="max-w-2xl mx-auto premium-card p-8 rounded-3xl bg-white border border-border flex flex-col justify-between hover:border-primary/20 transition-all duration-300 min-h-[220px]">
              <div className="space-y-4">
                <div className="flex gap-1">
                  {[...Array(5)].map((_, i) => (
                    <Star key={i} className="w-3.5 h-3.5 fill-amber-400 text-amber-400" />
                  ))}
                </div>
                <p className="text-xs md:text-sm text-muted leading-relaxed font-semibold italic">
                  "{quote}"
                </p>
              </div>

              <div className="flex items-center gap-3.5 mt-6 pt-4 border-t border-slate-100">
                <div className={`w-9 h-9 rounded-full bg-gradient-to-br ${color} flex items-center justify-center text-white font-extrabold text-sm shrink-0 shadow-sm`}>
                  {avatar}
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-bold text-foreground truncate">{name}</p>
                  <p className="text-[10px] text-muted truncate">{role}</p>
                  <p className="text-[9px] text-primary font-bold truncate">{company}</p>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Dots Indicator */}
      <div className="flex justify-center gap-2 mt-6">
        {testimonials.map((_, index) => (
          <button
            key={index}
            type="button"
            suppressHydrationWarning={true}
            onClick={() => setCurrentIndex(index)}
            className={`w-2 h-2 rounded-full transition-all duration-300 cursor-pointer
              ${currentIndex === index ? 'bg-[#3525cd] w-5' : 'bg-slate-200 hover:bg-slate-300'}`}
          />
        ))}
      </div>
    </div>
  )
}

// 📦 COMPONENT: Applicant status update + message button
// Client component (needs interactivity)

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import axios from 'axios'

interface Props {
  applicationId: string
  currentStatus: string
  seekerId?: string
  seekerName?: string
}

const statuses = ['applied', 'reviewed', 'interview', 'hired', 'rejected']

export default function ApplicantActions({
  applicationId,
  currentStatus,
  seekerId,
  seekerName,
}: Props) {
  const router = useRouter()
  const [updating, setUpdating] = useState(false)

  async function updateStatus(status: string) {
    setUpdating(true)
    try {
      await axios.put(`/api/applications/${applicationId}`, { status })
      router.refresh()
    } catch {
      console.error('Failed to update status')
    } finally {
      setUpdating(false)
    }
  }

  return (
    <div className="flex items-center gap-2">
      {/* Status dropdown */}
      <select
        value={currentStatus}
        onChange={e => updateStatus(e.target.value)}
        disabled={updating}
        className="text-xs px-2 py-1.5 rounded-xl border border-[#c7c4d8] bg-white text-[#464555] focus:outline-none focus:border-[#3525cd] disabled:opacity-60 cursor-pointer"
      >
        {statuses.map(s => (
          <option key={s} value={s} className="capitalize">{s}</option>
        ))}
      </select>

      {/* Message button */}
      {seekerId && (
        <a
          href={`/company/dashboard/messages?userId=${seekerId}&applicationId=${applicationId}`}
          className="text-xs px-3 py-1.5 rounded-xl border border-[#c7c4d8] text-[#464555] font-semibold hover:bg-[#eff4ff] hover:text-[#3525cd] transition-all"
        >
          💬 Message
        </a>
      )}
    </div>
  )
}

// 📦 COMPONENT: Admin approve/reject company
'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import axios from 'axios'
import { CheckCircle2, XCircle, Check, X, AlertTriangle } from 'lucide-react'

interface Props {
  companyId:    string
  isApproved:   boolean
  companyName:  string
  companyEmail: string
}

export default function AdminCompanyActions({
  companyId,
  isApproved,
  companyName,
  companyEmail,
}: Props) {
  const router  = useRouter()
  const [loading, setLoading]       = useState(false)
  const [showReject, setShowReject] = useState(false)
  const [reason, setReason]         = useState('')

  async function approve() {
    setLoading(true)
    try {
      await axios.put(`/api/admin/companies/${companyId}`, {
        action: 'approve',
        companyName,
        companyEmail,
      })
      router.refresh()
    } catch {
      console.error('Failed to approve company')
    } finally {
      setLoading(false)
    }
  }

  async function reject() {
    if (!reason.trim()) return
    setLoading(true)
    try {
      await axios.put(`/api/admin/companies/${companyId}`, {
        action: 'reject',
        reason,
        companyName,
        companyEmail,
      })
      setShowReject(false)
      router.refresh()
    } catch {
      console.error('Failed to reject company')
    } finally {
      setLoading(false)
    }
  }

  if (isApproved) {
    return (
      <div className="flex items-center gap-2 shrink-0">
        <span className="inline-flex items-center gap-1 text-[10px] font-extrabold px-3 py-1.5 rounded-xl bg-emerald-50 text-emerald-600 border border-emerald-200 uppercase tracking-wider">
          <CheckCircle2 className="w-3.5 h-3.5" />
          Approved
        </span>
        <button
          onClick={async () => {
            setLoading(true)
            await axios.put(`/api/admin/companies/${companyId}`, { action: 'revoke' })
            router.refresh()
            setLoading(false)
          }}
          disabled={loading}
          className="text-xs px-3.5 py-1.5 rounded-xl border border-slate-200 text-[#464555] hover:bg-rose-50 hover:text-rose-600 hover:border-rose-200 transition-all duration-200 font-semibold disabled:opacity-60 cursor-pointer active:scale-[0.98]"
        >
          Revoke
        </button>
      </div>
    )
  }

  return (
    <div className="shrink-0">
      {!showReject ? (
        <div className="flex gap-2">
          <button
            onClick={approve}
            disabled={loading}
            className="text-xs px-4 py-2 rounded-xl bg-emerald-600 text-white font-bold hover:bg-emerald-700 hover:shadow-sm active:scale-[0.98] transition-all disabled:opacity-60 flex items-center gap-1.5 cursor-pointer"
          >
            {loading ? (
              <svg className="w-4 h-4 animate-spin text-white" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
              </svg>
            ) : (
              <>
                <Check className="w-3.5 h-3.5" />
                Approve
              </>
            )}
          </button>

          <button
            onClick={() => setShowReject(true)}
            className="text-xs px-4 py-2 rounded-xl bg-rose-50 border border-rose-100 text-rose-600 font-bold hover:bg-rose-100 active:scale-[0.98] transition-all flex items-center gap-1.5 cursor-pointer"
          >
            <X className="w-3.5 h-3.5" />
            Reject
          </button>
        </div>
      ) : (
        <div className="space-y-2.5 max-w-[240px] md:max-w-xs animate-fade-in">
          <textarea
            rows={2.5}
            value={reason}
            onChange={e => setReason(e.target.value)}
            placeholder="Specify reason for rejection..."
            className="input-premium w-full px-3 py-2 text-xs bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:border-primary resize-none placeholder:text-muted/50"
          />
          <div className="flex gap-2">
            <button
              onClick={reject}
              disabled={loading || !reason.trim()}
              className="text-xs px-3.5 py-2 rounded-xl bg-rose-600 hover:bg-rose-700 text-white font-bold flex items-center gap-1 transition-all disabled:opacity-60 cursor-pointer active:scale-[0.98]"
            >
              Confirm Reject
            </button>
            <button
              onClick={() => setShowReject(false)}
              className="text-xs px-3.5 py-2 rounded-xl border border-slate-200 text-[#464555] hover:bg-slate-50 transition-all cursor-pointer font-semibold"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

// 📦 COMPONENT: Admin Users List Console
'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import axios from 'axios'
import { 
  Search, 
  Trash2, 
  ShieldAlert, 
  User, 
  Briefcase, 
  Shield, 
  CheckCircle, 
  AlertTriangle,
  Clock
} from 'lucide-react'

interface UserItem {
  _id: string
  name: string
  email: string
  role: string
  isEmailVerified: boolean
  createdAt: string | Date
}

interface Props {
  initialUsers: UserItem[]
  currentUserId: string
}

export default function AdminUsersList({ initialUsers, currentUserId }: Props) {
  const router = useRouter()
  const [users, setUsers] = useState<UserItem[]>(initialUsers)
  const [search, setSearch] = useState('')
  const [roleFilter, setRoleFilter] = useState<'all' | 'jobseeker' | 'recruiter' | 'admin'>('all')
  const [deletingId, setDeletingId] = useState<string | null>(null)
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null)

  // Filters
  const filteredUsers = users.filter(user => {
    const matchesSearch = 
      user.name.toLowerCase().includes(search.toLowerCase()) || 
      user.email.toLowerCase().includes(search.toLowerCase())

    const matchesRole = roleFilter === 'all' || user.role === roleFilter

    return matchesSearch && matchesRole
  })

  // Delete handler
  async function handleDelete(userId: string) {
    setDeletingId(userId)
    try {
      await axios.delete(`/api/admin/users/${userId}`)
      setUsers(prev => prev.filter(u => u._id !== userId))
      setConfirmDeleteId(null)
      router.refresh()
    } catch (err) {
      console.error('Failed to delete user:', err)
      alert('Error deleting user')
    } finally {
      setDeletingId(null)
    }
  }

  const roleStyles: Record<string, { bg: string; text: string; border: string; label: string; icon: any }> = {
    admin: { 
      bg: 'bg-rose-500/10', 
      text: 'text-rose-600', 
      border: 'border-rose-500/20', 
      label: 'Admin',
      icon: Shield
    },
    recruiter: { 
      bg: 'bg-primary/10', 
      text: 'text-primary', 
      border: 'border-primary/20', 
      label: 'Recruiter',
      icon: Briefcase
    },
    jobseeker: { 
      bg: 'bg-emerald-500/10', 
      text: 'text-emerald-600', 
      border: 'border-emerald-500/20', 
      label: 'Job Seeker',
      icon: User
    }
  }

  return (
    <div className="space-y-6">
      {/* Filters Toolbar */}
      <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-4 rounded-2xl border border-border shadow-xs">

        {/* Search */}
        <div className="relative w-full md:max-w-md">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-muted/50" />
          <input
            type="text"
            placeholder="Search users by name or email..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className="input-premium w-full pl-10 pr-4 py-2.5 rounded-xl text-xs placeholder:text-muted/50 focus:outline-none"
          />
        </div>

        {/* Role Pills */}
        <div className="flex items-center gap-1.5 overflow-x-auto w-full md:w-auto pb-1 md:pb-0">
          {(['all', 'jobseeker', 'recruiter', 'admin'] as const).map(role => {
            const active = roleFilter === role
            return (
              <button
                key={role}
                onClick={() => setRoleFilter(role)}
                className={`text-[10px] font-extrabold px-3.5 py-2 rounded-xl border uppercase tracking-wider transition-all duration-200 cursor-pointer shrink-0
                  ${active
                    ? 'bg-primary text-white border-primary shadow-sm'
                    : 'bg-slate-50 border-slate-100 text-[#464555] hover:bg-slate-100'
                  }`}
              >
                {role === 'all' ? 'All Users' : role === 'jobseeker' ? 'Job Seekers' : role === 'recruiter' ? 'Recruiters' : 'Admins'}
              </button>
            )
          })}
        </div>

      </div>

      {/* Users Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredUsers.map(user => {
          const isSelf = user._id === currentUserId
          const style = roleStyles[user.role] || roleStyles.jobseeker
          const Icon = style.icon
          const isConfirmed = confirmDeleteId === user._id

          return (
            <div 
              key={user._id} 
              className={`premium-card p-5 rounded-2xl flex flex-col justify-between relative overflow-hidden group hover:shadow-[0_8px_30px_rgba(79,70,229,0.02)]
                ${isConfirmed ? 'border-rose-300 bg-rose-50/10' : ''}`}
            >
              <div className="space-y-4">
                {/* Header info */}
                <div className="flex justify-between items-start">
                  <div className="flex items-center gap-2.5">
                    <div className={`w-9 h-9 rounded-xl ${style.bg} border ${style.border} flex items-center justify-center text-current`}>
                      <Icon className="w-4.5 h-4.5" />
                    </div>
                    <div>
                      <span className={`inline-flex items-center gap-1 text-[9px] font-extrabold px-2 py-0.5 rounded-md border uppercase tracking-wider ${style.bg} ${style.text} ${style.border}`}>
                        {style.label}
                      </span>
                    </div>
                  </div>

                  {/* Verification Status */}
                  <span className={`inline-flex items-center gap-1 text-[9px] font-extrabold px-2.5 py-0.5 rounded-full border uppercase tracking-wider
                    ${user.isEmailVerified
                      ? 'bg-emerald-50 text-emerald-600 border-emerald-100'
                      : 'bg-amber-50 text-amber-600 border-amber-100'
                    }`}>
                    {user.isEmailVerified ? (
                      <>
                        <CheckCircle className="w-2.5 h-2.5" />
                        Verified
                      </>
                    ) : (
                      <>
                        <Clock className="w-2.5 h-2.5" />
                        Pending
                      </>
                    )}
                  </span>
                </div>

                {/* Name & Email */}
                <div>
                  <h3 className="text-xs font-bold text-foreground truncate group-hover:text-primary transition-colors">
                    {user.name}
                  </h3>
                  <p className="text-[10px] text-muted truncate mt-0.5">{user.email}</p>
                </div>
              </div>

              {/* Footer Actions */}
              <div className="mt-4 pt-3.5 border-t border-slate-100/50 flex justify-between items-center text-[10px] text-muted font-bold">
                <span>Joined {new Date(user.createdAt).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}</span>

                {isSelf ? (
                  <span className="text-[9px] uppercase tracking-wider text-rose-500 font-extrabold bg-rose-50 border border-rose-100 px-2 py-0.5 rounded-md">
                    Logged In
                  </span>
                ) : isConfirmed ? (
                  <div className="flex gap-1.5 items-center">
                    <button
                      onClick={() => handleDelete(user._id)}
                      disabled={deletingId === user._id}
                      className="px-2.5 py-1 rounded-lg bg-rose-600 text-white font-bold hover:bg-rose-700 active:scale-95 disabled:opacity-50 cursor-pointer"
                    >
                      {deletingId === user._id ? 'Deleting...' : 'Confirm'}
                    </button>
                    <button
                      onClick={() => setConfirmDeleteId(null)}
                      className="px-2.5 py-1 rounded-lg border border-slate-200 hover:bg-slate-50 text-[#464555] font-semibold cursor-pointer"
                    >
                      Cancel
                    </button>
                  </div>
                ) : (
                  <button
                    onClick={() => setConfirmDeleteId(user._id)}
                    className="p-1.5 rounded-lg text-muted/60 hover:text-rose-600 hover:bg-rose-50 border border-transparent hover:border-rose-100 transition-all cursor-pointer"
                    title="Delete User"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                )}
              </div>
            </div>
          )
        })}
      </div>

      {filteredUsers.length === 0 && (
        <div className="premium-card p-12 text-center rounded-2xl border border-dashed flex flex-col items-center justify-center">
          <ShieldAlert className="w-10 h-10 text-muted/40 mb-3" />
          <p className="text-sm font-bold text-foreground">No users found</p>
          <p className="text-xs text-muted mt-1">Try adjusting your search criteria or role filters</p>
        </div>
      )}
    </div>
  )
}

// 📦 COMPONENT: Apply button with cover letter modal
'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import axios from 'axios'
import Link from 'next/link'

interface Props {
  jobId:          string
  isLoggedIn:     boolean
  isJobSeeker:    boolean
  alreadyApplied: boolean
}

export default function ApplyButton({
  jobId,
  isLoggedIn,
  isJobSeeker,
  alreadyApplied,
}: Props) {
  const router = useRouter()
  const [open, setOpen]               = useState(false)
  const [coverLetter, setCoverLetter] = useState('')
  const [loading, setLoading]         = useState(false)
  const [error, setError]             = useState('')
  const [success, setSuccess]         = useState(false)

  async function handleApply() {
    setError('')
    setLoading(true)
    try {
      await axios.post('/api/applications', { jobId, coverLetter })
      setSuccess(true)
      setOpen(false)
      router.refresh()
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to apply')
    } finally {
      setLoading(false)
    }
  }

  if (success || alreadyApplied) {
    return (
      <div className="w-full py-3 rounded-xl bg-green-50 border border-green-200 text-green-700 text-sm font-semibold text-center">
        ✅ Already Applied
      </div>
    )
  }

  if (!isLoggedIn) {
    return (
      <Link
        href="/login"
        className="block w-full py-3 rounded-xl bg-[#3525cd] text-white text-sm font-semibold text-center hover:opacity-90 transition-opacity"
      >
        Login to Apply
      </Link>
    )
  }

  if (!isJobSeeker) {
    return (
      <div className="w-full py-3 rounded-xl bg-[#eff4ff] text-[#464555] text-sm text-center">
        Only job seekers can apply
      </div>
    )
  }

  return (
    <>
      <button
        onClick={() => setOpen(true)}
        className="w-full py-3 rounded-xl bg-[#3525cd] text-white text-sm font-semibold hover:opacity-90 active:scale-[0.98] transition-all shadow-[0px_4px_12px_rgba(53,37,205,0.2)]"
      >
        Apply Now →
      </button>

      {/* Modal */}
      {open && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl border border-[#c7c4d8] p-6 max-w-md w-full shadow-xl">
            <h3 className="font-bold text-lg text-[#0b1c30] mb-1">Apply for this job</h3>
            <p className="text-sm text-[#777587] mb-4">
              Your saved resume will be sent. Add a cover letter to stand out.
            </p>

            {error && (
              <div className="mb-4 px-4 py-3 rounded-xl bg-[#ffdad6] text-[#93000a] text-sm">
                {error}
              </div>
            )}

            <div className="mb-4">
              <label className="block text-xs font-medium text-[#464555] mb-1.5">
                Cover Letter <span className="text-[#777587]">(optional)</span>
              </label>
              <textarea
                rows={5}
                value={coverLetter}
                onChange={e => setCoverLetter(e.target.value)}
                placeholder="Tell the recruiter why you're a great fit for this role..."
                className="w-full px-4 py-3 bg-[#f8f9ff] border border-[#c7c4d8] rounded-xl text-sm focus:outline-none focus:border-[#3525cd] focus:ring-1 focus:ring-[#3525cd] resize-none transition-all"
              />
            </div>

            <div className="flex gap-3">
              <button
                onClick={() => setOpen(false)}
                className="flex-1 py-2.5 rounded-xl border border-[#c7c4d8] text-sm font-semibold text-[#464555] hover:bg-[#eff4ff] transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleApply}
                disabled={loading}
                className="flex-1 py-2.5 rounded-xl bg-[#3525cd] text-white text-sm font-semibold hover:opacity-90 disabled:opacity-60 flex items-center justify-center gap-2 transition-all"
              >
                {loading ? (
                  <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                  </svg>
                ) : 'Submit Application'}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  )
}

const fs = require('fs');
const path = require('path');
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

// ── Load Environment Variables ──
let MONGODB_URI = '';
try {
  const envPath = path.join(__dirname, '..', '.env.local');
  if (fs.existsSync(envPath)) {
    const envContent = fs.readFileSync(envPath, 'utf8');
    const match = envContent.match(/MONGODB_URI\s*=\s*([^\r\n]+)/);
    if (match) MONGODB_URI = match[1].replace(/['"]/g, '').trim();
  }
} catch (e) {
  console.log('Error reading .env.local:', e.message);
}

if (!MONGODB_URI) {
  try {
    const envPath = path.join(__dirname, '..', '.env');
    if (fs.existsSync(envPath)) {
      const envContent = fs.readFileSync(envPath, 'utf8');
      const match = envContent.match(/MONGODB_URI\s*=\s*([^\r\n]+)/);
      if (match) MONGODB_URI = match[1].replace(/['"]/g, '').trim();
    }
  } catch (e) {
    console.log('Error reading .env:', e.message);
  }
}

if (!MONGODB_URI) {
  console.error('❌ MONGODB_URI could not be found in .env.local or .env');
  process.exit(1);
}

console.log('🔌 Connecting to MongoDB...');

// ── Inline Models (to avoid ESM compile conflicts) ──
const UserSchema = new mongoose.Schema({
  name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  password: { type: String, required: true },
  role: { type: String, enum: ['jobseeker', 'recruiter', 'admin'], default: 'jobseeker' },
  isEmailVerified: { type: Boolean, default: false },
}, { timestamps: true });

const CompanySchema = new mongoose.Schema({
  name: { type: String, required: true },
  email: { type: String, required: true },
  location: { type: String, default: '' },
  industry: { type: String, default: '' },
  ownerId: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
  isEmailVerified: { type: Boolean, default: false },
  isAdminApproved: { type: Boolean, default: false },
  subscription: {
    plan: { type: String, enum: ['free', 'pro', 'enterprise'], default: 'free' },
    status: { type: String, default: 'inactive' }
  }
}, { timestamps: true });

const User = mongoose.models.User || mongoose.model('User', UserSchema);
const Company = mongoose.models.Company || mongoose.model('Company', CompanySchema);

async function seed() {
  try {
    await mongoose.connect(MONGODB_URI);
    console.log('✅ Connected to Database.');

    const salt = bcrypt.genSaltSync(10);
    const passwordHash = bcrypt.hashSync('password123', salt);

    // 1. Create Admin
    const adminEmail = 'admin@workhire.com';
    let admin = await User.findOne({ email: adminEmail });
    if (!admin) {
      admin = await User.create({
        name: 'Platform Admin',
        email: adminEmail,
        password: passwordHash,
        role: 'admin',
        isEmailVerified: true,
      });
      console.log(`👤 Admin created: ${adminEmail}`);
    } else {
      console.log(`ℹ️ Admin already exists: ${adminEmail}`);
    }

    // 2. Create Recruiter
    const recruiterEmail = 'recruiter@workhire.com';
    let recruiter = await User.findOne({ email: recruiterEmail });
    if (!recruiter) {
      recruiter = await User.create({
        name: 'Robert Recruiter',
        email: recruiterEmail,
        password: passwordHash,
        role: 'recruiter',
        isEmailVerified: true,
      });
      console.log(`👤 Recruiter created: ${recruiterEmail}`);
    } else {
      console.log(`ℹ️ Recruiter already exists: ${recruiterEmail}`);
    }

    // 3. Create Company profile for Recruiter
    let company = await Company.findOne({ ownerId: recruiter._id });
    if (!company) {
      company = await Company.create({
        name: 'Acme Recruiting Corp',
        email: recruiterEmail,
        location: 'Mumbai, MH',
        industry: 'Technology',
        ownerId: recruiter._id,
        isEmailVerified: true,
        isAdminApproved: true,
        subscription: {
          plan: 'pro',
          status: 'active'
        }
      });
      console.log(`🏢 Company profile created: "${company.name}" (Approved & Pro Plan Active)`);
    } else {
      // Ensure it is approved for testing
      company.isAdminApproved = true;
      await company.save();
      console.log(`ℹ️ Company already exists for Recruiter (Ensured Admin Approved).`);
    }

    // 4. Create Job Seeker
    const seekerEmail = 'seeker@workhire.com';
    let seeker = await User.findOne({ email: seekerEmail });
    if (!seeker) {
      seeker = await User.create({
        name: 'John Seeker',
        email: seekerEmail,
        password: passwordHash,
        role: 'jobseeker',
        isEmailVerified: true,
      });
      console.log(`👤 Job Seeker created: ${seekerEmail}`);
    } else {
      console.log(`ℹ️ Seeker already exists: ${seekerEmail}`);
    }

    console.log('\n🎉 DB Seeded Successfully!');
    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');
    console.log('🔑 Credentials (Password for all: password123)');
    console.log(`  • Admin:     ${adminEmail}`);
    console.log(`  • Recruiter: ${recruiterEmail}`);
    console.log(`  • Seeker:    ${seekerEmail}`);
    console.log('━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━');

  } catch (error) {
    console.error('❌ Seeding failed:', error.message);
  } finally {
    await mongoose.connection.close();
    console.log('🔌 DB Connection closed.');
    process.exit(0);
  }
}

seed();

import connectDB from '@/lib/db'
import Notification from '@/models/Notification'
import { NotificationType } from '@/types'

export async function createNotification({
  userId,
  type,
  message,
  link,
}: {
  userId: string | any
  type: NotificationType
  message: string
  link?: string
}) {
  try {
    await connectDB()
    await Notification.create({
      userId,
      type,
      message,
      link,
    })
  } catch (error) {
    console.error('Failed to create notification:', error)
  }
}
